      const { data: salesData } = await supabase.from('agent_sales').select('*');
      if (salesData) setSales(salesData);

      const { data: payoutsData } = await supabase.from('payout_requests').select('*');
      if (payoutsData) setPayouts(payoutsData);

      const { data: settingsData } = await supabase.from('site_settings').select('*').eq('id', 1).single();
      if (settingsData) {
        setSettings({ ...DEFAULT_SETTINGS, ...settingsData });
      }
    } catch (error) {
      console.error('Fetch error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const addCategory = async (name: string): Promise<Category> => {
    const newCat = { id: Date.now().toString(), name };
    const { data, error } = await supabase.from('blog_categories').insert([newCat]).select().single();
    if (error) {
      setCategories(prev => [...prev, newCat]);
      return newCat;
    }
    setCategories(prev => [...prev, data]);
    return data;
  };

  const addAgent = async (agent: Partial<Agent>): Promise<Agent> => {
    const newAgent = {
      ...agent,
      id: Date.now().toString(),
      referral_code: `FORGE${Math.floor(Math.random() * 9000) + 1000}`,
      status: 'Pending',
      date_joined: new Date().toISOString(),
      total_sales: 0,
      total_commission: 0,
      available_balance: 0,
      pending_balance: 0,
      total_clicks: 0,
      total_leads: 0
    } as Agent;

    const { error } = await supabase.from('agents').insert([newAgent]);
    if (error) {
      setAgents(prev => [...prev, newAgent]);
      return newAgent;
    }
    setAgents(prev => [...prev, newAgent]);
    return newAgent;
  };

  const updateAgent = async (agent: Agent) => {
    await supabase.from('agents').update(agent).eq('id', agent.id);
    setAgents(prev => prev.map(a => a.id === agent.id ? agent : a));
  };

  const getAgentSales = (agentId: string) => sales.filter(s => s.agent_id === agentId);
  const getAgentPayouts = (agentId: string) => payouts.filter(p => p.agent_id === agentId);

  const requestPayout = async (payout: PayoutRequest) => {
    await supabase.from('payout_requests').insert([payout]);
    setPayouts(prev => [payout, ...prev]);
  };

  const updatePayoutStatus = async (id: string, status: PayoutRequest['status']) => {
    await supabase.from('payout_requests').update({ status }).eq('id', id);
    setPayouts(prev => prev.map(p => p.id === id ? { ...p, status } : p));
  };

  const addSaleManually = async (sale: AgentSale) => {
    await supabase.from('agent_sales').insert([sale]);
    setSales(prev => [sale, ...prev]);
  };

  const updateSaleStatus = async (id: string, status: AgentSale['deal_status']) => {
    await supabase.from('agent_sales').update({ deal_status: status }).eq('id', id);
    setSales(prev => prev.map(s => s.id === id ? { ...s, deal_status: status } : s));
  };

  const addProperty = async (property: Property) => {
    await supabase.from('properties').insert([property]);
    setProperties(prev => [property, ...prev]);
  };

  const updateProperty = async (updatedProperty: Property) => {
    await supabase.from('properties').update(updatedProperty).eq('id', updatedProperty.id);
    setProperties(prev => prev.map(p => p.id === updatedProperty.id ? updatedProperty : p));
  };

  const deleteProperty = async (id: string) => {
    await supabase.from('properties').delete().eq('id', id);
    setProperties(prev => prev.filter(p => p.id !== id));
  };

  const addLead = async (lead: Lead) => {
    await supabase.from('leads').insert([lead]);
    setLeads(prev => [lead, ...prev]);
  };

  const updateLeadStatus = async (id: string, status: Lead['status']) => {
    await supabase.from('leads').update({ status }).eq('id', id);
    setLeads(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  const addSubscriber = async (email: string) => {
    if (subscribers.some(s => s.email === email)) return;
    const newSubscriber: Subscriber = { id: Date.now().toString(), email, date: new Date().toISOString() };
    await supabase.from('subscribers').insert([newSubscriber]);
    setSubscribers(prev => [newSubscriber, ...prev]);
  };

  const addPost = async (post: BlogPost) => {
    await supabase.from('posts').insert([post]);
    setPosts(prev => [post, ...prev]);
  };

  const updatePost = async (updatedPost: BlogPost) => {
    await supabase.from('posts').update(updatedPost).eq('id', updatedPost.id);
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
  };

  const deletePost = async (id: string) => {
    await supabase.from('posts').delete().eq('id', id);
    setPosts(prev => prev.filter(p => p.id !== id));
  };

  const updateSettings = async (newSettings: SiteSettings) => {
    await supabase.from('site_settings').update(newSettings).eq('id', 1);
    setSettings(newSettings);
  };

  const seedDatabase = async () => {
    setIsLoading(true);
    try {
      await supabase.from('site_settings').upsert({ id: 1, ...DEFAULT_SETTINGS });
      await fetchData();
      alert("System initialized.");
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <PropertyContext.Provider value={{ 
      properties, leads, subscribers, posts, categories, agents, sales, payouts, settings, isLoading,
      addProperty, updateProperty, deleteProperty, getProperty: (id) => properties.find(p => p.id === id), getPropertyBySlug: (slug) => properties.find(p => p.slug === slug),
      addLead, updateLeadStatus, addSubscriber, updateSettings,
      addPost, updatePost, deletePost, getPost: (id) => posts.find(p => p.id === id), getPostBySlug: (slug) => posts.find(p => p.slug === slug),
      addCategory,
      addAgent, updateAgent, getAgentSales, getAgentPayouts, requestPayout, updatePayoutStatus, addSaleManually, updateSaleStatus,
      seedDatabase
    }}>
      {children}
    </PropertyContext.Provider>
  );
};

export const useProperties = () => {
  const context = useContext(PropertyContext);
  if (!context) throw new Error('useProperties must be used within a PropertyProvider');
  return context;
};

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useProperties } from '../context/PropertyContext';
import { Lock, Mail, User, Phone, Eye, EyeOff, ArrowRight, ShieldCheck, Loader2 } from 'lucide-react';

export const AgentPortal: React.FC = () => {
  const [mode, setMode] = useState<'login' | 'signup' | 'success'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const { agentLogin } = useAuth();
  const { addAgent, settings } = useProperties();
  const navigate = useNavigate();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    // In a real app, this would be an async call to your backend
    setTimeout(() => {
      const success = agentLogin(email, password);
      if (success) {
        navigate('/agent/dashboard');
      } else {
        setError('Invalid credentials or account pending approval.');
        setIsLoading(false);
      }
    }, 1000);
  };

  const handleSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      await addAgent({ name, email, phone });
      setMode('success');
    } catch (err: any) {
      setError(err.message || 'Signup failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  if (mode === 'success') {
    return (
      <div className="min-h-screen bg-forge-navy flex items-center justify-center p-6">
        <div className="bg-white max-w-lg w-full p-10 rounded-2xl shadow-2xl text-center">
          <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <ShieldCheck size={40} />
          </div>
          <h2 className="text-3xl font-serif text-forge-navy mb-4">Registration Successful</h2>
          <p className="text-slate-600 mb-8 leading-relaxed">
            Welcome to the elite circle. Your application is being reviewed by our corporate team. You can now join our community of high-performing realtors.
          </p>
          <div className="space-y-4">
            <a 
              href={settings.whatsapp_group_link || 'https://chat.whatsapp.com/DRsRpTeucuK6bIfSu0pvje?mode=gi_t'} 
              target="_blank" 
              rel="noopener noreferrer"
              className="block w-full bg-green-500 text-white py-4 rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-green-600 transition-all shadow-lg shadow-green-200"
            >
              Join Official Agent WhatsApp
            </a>
            <button 
              onClick={() => setMode('login')}
              className="block w-full border border-slate-200 text-slate-500 py-4 rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-50 transition-all"
            >
              Return to Login
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-forge-navy flex flex-col md:flex-row overflow-hidden">
      {/* Branding Side */}
      <div className="md:w-1/2 relative bg-forge-dark overflow-hidden flex flex-col justify-center p-12 lg:p-24">
        <div className="absolute inset-0 z-0">
           <img 
            src="https://images.unsplash.com/photo-1560518883-ce09059eeffa?q=80&w=2000" 
            className="w-full h-full object-cover opacity-20" 
            alt="Luxury Architecture"
           />
           <div className="absolute inset-0 bg-gradient-to-r from-forge-dark via-transparent to-transparent" />
        </div>

        <div className="relative z-10">
          <Link to="/" className="inline-flex flex-col mb-16">
            <span className="text-3xl font-serif font-bold text-white tracking-widest">THE FORGE</span>
            <span className="text-xs uppercase tracking-[0.4em] text-forge-gold">Properties</span>
          </Link>
          <h1 className="text-4xl lg:text-6xl font-serif text-white mb-6 leading-tight">
            Accredited <br /> <span className="text-forge-gold">Agent Portal</span>
          </h1>
          <p className="text-slate-400 text-lg max-w-md leading-relaxed">
            The exclusive platform for Nigeria's leading real estate professionals. Track sales, manage referrals, and access off-market inventory.
          </p>
        </div>
      </div>

      {/* Auth Side */}
      <div className="md:w-1/2 bg-slate-50 flex items-center justify-center p-8 lg:p-20">
        <div className="w-full max-w-md">
          <div className="bg-white p-10 rounded-2xl shadow-xl border border-slate-100">
            <div className="flex gap-4 mb-8">
              <button 
                onClick={() => setMode('login')}
                className={`flex-1 pb-3 text-xs font-bold uppercase tracking-widest transition-all ${mode === 'login' ? 'text-forge-navy border-b-2 border-forge-gold' : 'text-slate-400'}`}
              >
                Login
              </button>
              <button 
                onClick={() => setMode('signup')}
                className={`flex-1 pb-3 text-xs font-bold uppercase tracking-widest transition-all ${mode === 'signup' ? 'text-forge-navy border-b-2 border-forge-gold' : 'text-slate-400'}`}
              >
                Sign Up
              </button>
            </div>

            {error && (
              <div className="bg-red-50 text-red-600 p-4 rounded-xl text-xs font-bold mb-6 border border-red-100">
                {error}
              </div>
            )}

            <form className="space-y-5" onSubmit={mode === 'login' ? handleLogin : handleSignup}>
              {mode === 'signup' && (
                <>
                  <div>
                    <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Full Name</label>
                    <div className="relative">
                      <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                      <input 
                        type="text" 
                        required 
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        className="w-full bg-slate-50 border border-slate-200 pl-12 pr-4 py-4 rounded-xl text-sm focus:border-forge-gold focus:outline-none transition-all"
                        placeholder="John Doe"
